import { ProjectCard } from "@/components/ProjectCard";
import { projects } from "@/lib/projects";

export default function ProjectsPage() {
  return (
    <main>
      <div className="page-shell">
        <section className="page-header animate-rise">
          <p className="eyebrow">Portfolio</p>
          <h1>Projects &amp; Case Studies</h1>
          <p>
            Company work is presented as architecture case studies (no source code).
            Personal projects include full GitHub code and live demos you can run.
          </p>
        </section>

        <div className="filter-tabs" style={{ justifyContent: "flex-start" }}>
          {["All", "Full-Stack", "Java Backend", "API", "UI/UX"].map((tab) => (
            <button key={tab} className={`filter-tab${tab === "All" ? " active" : ""}`}>{tab}</button>
          ))}
        </div>

        <section className="project-grid">
          {projects.map((project) => (
            <ProjectCard key={project.slug} project={project} />
          ))}
        </section>
      </div>
    </main>
  );
}
